// PATCH(library): FlySoar.ai price source. Not generated by Printing Press —
// FlySoar has no OpenAPI spec; this is a hand-written backend alongside the
// Google Flights and Kayak sources. See internal/soar/soar.go and
// .printing-press-patches/soar-flysoar-price-source.json.

package cli

import (
	"context"
	"encoding/json"
	"fmt"
	"sort"
	"strconv"
	"strings"
	"text/tabwriter"

	"github.com/mvanhorn/printing-press-library/library/travel/flight-goat/internal/soar"

	"github.com/spf13/cobra"
)

// newSoarCmd wires the `soar` command: a FlySoar.ai price search for a specific
// route/date. FlySoar is a Duffel-backed metasearch with an anonymous streaming
// endpoint — no API key. It parallels the headline `flights` (Google) and the
// Kayak commands as a third, independent price source, and is the one whose
// fares come straight off Duffel's aggregated NDC + GDS content.
func newSoarCmd(flags *rootFlags) *cobra.Command {
	var returnDate, cabin string
	var passengers int
	var stopsTokens, airlines []string

	cmd := &cobra.Command{
		Use:         "soar <origin> <destination> <date>",
		Annotations: map[string]string{"mcp:read-only": "true"},
		Short:       "Search FlySoar.ai (Duffel) for a specific date (free, no API key required)",
		Long: `soar queries FlySoar.ai — a Duffel-backed flight metasearch — for a route and
date and returns real prices, durations, airlines, and leg details. Its fares
come from Duffel's aggregated NDC + GDS content, which often differs from what
Google Flights surfaces, so it's a useful second opinion on price. No API key,
no auth, just results — plus a deep link to open and book the same search on
flysoar.ai. Prices are always in USD (FlySoar's anonymous endpoint is USD-only).`,
		Example: `  # Cheapest SEA -> DEN on Sep 21
  flight-goat-pp-cli soar SEA DEN 2026-09-21

  # First class, one-way, JSON for agents
  flight-goat-pp-cli soar SEA DEN 2026-09-21 --class first --json

  # Round trip in business class
  flight-goat-pp-cli soar JFK LHR 2026-07-15 --return 2026-07-22 --class business

  # Nonstop or one-stop, on Delta or United only
  flight-goat-pp-cli soar DCA IAH 2026-09-23 --class first --stops 0,1 --airlines DL,UA

  # Two passengers
  flight-goat-pp-cli soar LHR DXB 2026-05-10 --passengers 2`,
		Args: cobra.ExactArgs(3),
		RunE: func(cmd *cobra.Command, args []string) error {
			origin := strings.ToUpper(args[0])
			destination := strings.ToUpper(args[1])
			departureDate := args[2]

			stops, err := parseSoarStops(stopsTokens)
			if err != nil {
				return err
			}
			for i := range airlines {
				airlines[i] = strings.ToUpper(strings.TrimSpace(airlines[i]))
			}

			opts := soar.SearchOptions{
				Origin:        origin,
				Destination:   destination,
				DepartureDate: departureDate,
				ReturnDate:    returnDate,
				CabinClass:    cabin,
				Passengers:    passengers,
				Stops:         stops,
				Airlines:      airlines,
			}

			if flags.dryRun {
				fmt.Fprintf(cmd.OutOrStdout(), "soar.Search(%s -> %s on %s)", opts.Origin, opts.Destination, opts.DepartureDate)
				if opts.ReturnDate != "" {
					fmt.Fprintf(cmd.OutOrStdout(), " return=%s", opts.ReturnDate)
				}
				if opts.CabinClass != "" {
					fmt.Fprintf(cmd.OutOrStdout(), " class=%s", strings.ToLower(opts.CabinClass))
				}
				if len(opts.Stops) > 0 {
					fmt.Fprintf(cmd.OutOrStdout(), " stops=%v", opts.Stops)
				}
				if len(opts.Airlines) > 0 {
					fmt.Fprintf(cmd.OutOrStdout(), " airlines=%s", strings.Join(opts.Airlines, ","))
				}
				fmt.Fprintf(cmd.OutOrStdout(), "\nurl: %s\n(dry run - no request sent)\n",
					soar.SearchURL(opts.Origin, opts.Destination, opts.DepartureDate, opts.ReturnDate, opts.CabinClass, opts.Stops, opts.Airlines))
				return nil
			}

			// Honor an explicit --timeout; otherwise let soar.Search apply its
			// own generous default (FlySoar SSE streams can run several seconds).
			ctx := cmd.Context()
			if cmd.Flags().Changed("timeout") && flags.timeout > 0 {
				var cancel context.CancelFunc
				ctx, cancel = context.WithTimeout(ctx, flags.timeout)
				defer cancel()
			}
			result, err := soar.Search(ctx, opts)
			if err != nil {
				return err
			}

			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				bts, _ := json.MarshalIndent(result, "", "  ")
				fmt.Fprintln(cmd.OutOrStdout(), string(bts))
				return nil
			}

			fmt.Fprintf(cmd.ErrOrStderr(), "%d flights found for %s -> %s on %s (source: %s)\n",
				result.Count, opts.Origin, opts.Destination, opts.DepartureDate, result.Source)
			if result.Note != "" {
				fmt.Fprintf(cmd.ErrOrStderr(), "note: %s\n", result.Note)
			}

			if result.Count > 0 {
				tw := tabwriter.NewWriter(cmd.OutOrStdout(), 0, 0, 2, ' ', 0)
				fmt.Fprintln(tw, "PRICE\tDURATION\tSTOPS\tAIRLINES\tDEPART\tARRIVE")
				limit := 15
				for i, f := range result.Flights {
					if i >= limit {
						fmt.Fprintf(cmd.ErrOrStderr(), "... and %d more (use --json for full list)\n", len(result.Flights)-limit)
						break
					}
					carriers := map[string]bool{}
					for _, l := range f.Legs {
						if l.Airline.Code != "" {
							carriers[l.Airline.Code] = true
						}
					}
					carrierList := make([]string, 0, len(carriers))
					for c := range carriers {
						carrierList = append(carrierList, c)
					}
					sort.Strings(carrierList)
					depart, arrive := "", ""
					if len(f.Legs) > 0 {
						depart = trimTime(f.Legs[0].DepartureTime)
						arrive = trimTime(f.Legs[len(f.Legs)-1].ArrivalTime)
					}
					fmt.Fprintf(tw, "%s\t%s\t%d\t%s\t%s\t%s\n",
						soarPrice(f.Currency, f.Price), minutesToHM(f.DurationMinutes), f.Stops, strings.Join(carrierList, ","), depart, arrive)
				}
				tw.Flush()
			}

			fmt.Fprintf(cmd.OutOrStdout(), "\nbook via FlySoar (flight-goat prices, it doesn't book):\n")
			fmt.Fprintf(cmd.OutOrStdout(), "  iMessage %s: %q\n", result.Booking.IMessageAgent, result.Booking.Request)
			fmt.Fprintf(cmd.OutOrStdout(), "  iMessage link: %s\n", result.Booking.IMessageURL)
			fmt.Fprintf(cmd.OutOrStdout(), "  web:           %s\n", result.Booking.WebURL)
			return nil
		},
	}

	cmd.Flags().StringVarP(&returnDate, "return", "r", "", "Return date for round-trip (YYYY-MM-DD)")
	cmd.Flags().StringVarP(&cabin, "class", "c", "", "Cabin class: economy, premium_economy, business, first")
	cmd.Flags().IntVarP(&passengers, "passengers", "p", 1, "Number of passengers")
	cmd.Flags().StringSliceVar(&stopsTokens, "stops", nil, "Allowed stop counts (comma list): 0=nonstop, 1, 2. E.g. --stops 0,1")
	cmd.Flags().StringSliceVarP(&airlines, "airlines", "a", nil, "Whitelist airlines by IATA code (comma list): e.g. --airlines DL,UA")
	return cmd
}

// parseSoarStops turns --stops tokens into a set of allowed stop counts,
// matching FlySoar's ?stops=0,1 GUI param. Accepts integers (0, 1, 2, …) and
// the aliases "nonstop"/"non_stop"/"non-stop"/"direct" for 0.
func parseSoarStops(tokens []string) ([]int, error) {
	if len(tokens) == 0 {
		return nil, nil
	}
	out := make([]int, 0, len(tokens))
	for _, t := range tokens {
		tok := strings.ToLower(strings.TrimSpace(t))
		if tok == "" {
			continue
		}
		switch tok {
		case "nonstop", "non_stop", "non-stop", "direct":
			out = append(out, 0)
			continue
		}
		n, err := strconv.Atoi(tok)
		if err != nil || n < 0 {
			return nil, fmt.Errorf("invalid --stops value %q: use stop counts like 0, 1, 2 (0 = nonstop)", t)
		}
		out = append(out, n)
	}
	return out, nil
}

// soarPrice formats a FlySoar fare with cents. The shared formatPrice helper
// rounds to whole units (%.0f), which is fine for Google Flights' typically
// whole-dollar quotes but drops the cents FlySoar returns (e.g. 94.98 -> "95").
func soarPrice(currency string, price float64) string {
	currency = strings.ToUpper(strings.TrimSpace(currency))
	if currency == "" {
		currency = "USD"
	}
	return fmt.Sprintf("%s %.2f", currency, price)
}
